import React, { useState, useEffect } from 'react';
import { useCalendar } from '../context/CalendarContext';

const TaskForm = ({ selectedDate, onClose }) => {
    const { addTask } = useCalendar();
    const [taskData, setTaskData] = useState({
        title: '',
        description: '',
        startDate: selectedDate,
        endDate: selectedDate,
        time: '',
        color: '#007bff'
    });

    // Log when form is mounted with selected date
    useEffect(() => {
        console.log('TaskForm mounted with date:', selectedDate);
        setTaskData(prev => ({
            ...prev,
            startDate: selectedDate,
            endDate: selectedDate
        }));
    }, [selectedDate]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        e.stopPropagation();
        
        console.log('Submitting task:', taskData);
        
        try {
            // Validate required fields
            if (!taskData.title) {
                throw new Error('Title is required');
            }
            if (!taskData.startDate) {
                throw new Error('Start date is required');
            }

            // Add task with manual flag
            const result = await addTask(taskData, true);
            console.log('Task addition result:', result);
            
            if (result) {
                console.log('Task added successfully');
                onClose();
            }
        } catch (error) {
            console.error('Failed to add task:', error);
            alert(`Failed to add task: ${error.message}`);
        }
    };

    const handleInputChange = (e, field) => {
        console.log(`Updating ${field}:`, e.target.value);
        setTaskData(prev => ({
            ...prev,
            [field]: e.target.value
        }));
    };

    return (
        <form onSubmit={handleSubmit} onClick={e => e.stopPropagation()} className="task-form">
            <input
                type="text"
                value={taskData.title}
                onChange={e => handleInputChange(e, 'title')}
                placeholder="Task title"
                required
            />
            <textarea
                value={taskData.description}
                onChange={e => handleInputChange(e, 'description')}
                placeholder="Description (optional)"
            />
            <input
                type="time"
                value={taskData.time}
                onChange={e => handleInputChange(e, 'time')}
            />
            <input
                type="color"
                value={taskData.color}
                onChange={e => handleInputChange(e, 'color')}
            />
            <div className="form-buttons">
                <button type="submit">Add Task</button>
                <button type="button" onClick={e => {
                    e.stopPropagation();
                    onClose();
                }}>Cancel</button>
            </div>
        </form>
    );
};

export default TaskForm;
